// src/pages/CreateGroup.js

import React, { useState } from 'react';
import axios from 'axios'; // Pour envoyer les requêtes HTTP

const CreateGroup = ({ currentUser }) => {
    const [groupName, setGroupName] = useState('');
    const [members, setMembers] = useState([currentUser.username]); // L'utilisateur qui crée le groupe est membre
    const [error, setError] = useState('');

    const handleCreateGroup = () => {
        if (!groupName) {
            setError("Le nom du groupe ne peut pas être vide.");
            return;
        }

        // Envoie les données du nouveau groupe au backend
        axios.post('http://ton-api.com/groups', {
            name: groupName,
            members: members,
            creator: currentUser.username,
        })
        .then(response => {
            // Redirige vers la page "Mes Groupes" après la création
            window.location.href = '/my-groups';
        })
        .catch(error => {
            console.error("Erreur lors de la création du groupe:", error);
            setError("Une erreur est survenue lors de la création du groupe.");
        });
    };

    return (
        <div className="create-group-page">
            <h1>Créer un Nouveau Groupe</h1>
            <input
                type="text"
                placeholder="Nom du groupe"
                value={groupName}
                onChange={e => setGroupName(e.target.value)}
            />
            {error && <p className="error">{error}</p>}
            <button onClick={handleCreateGroup}>Créer</button>
        </div>
    );
};

export default CreateGroup;
